mapper.select:
SELECT
	COUNT(1) companyJobNum
FROM
	company_job b
WHERE b.department_id = #{id}

	AND b.tenant_id = #{tenantId}

SELECT a.id, a.`name` title, a.parent_id parentId, CASE a.parent_id WHEN '0' THEN true ELSE true END isLast, '[{"type": "0", "isChecked": "0"}]' checkArr, CASE a.parent_id WHEN '0' THEN '1' ELSE '2' END level FROM company_department a WHERE a.company_id = #{companyId}
AND a.tenant_id = #{tenantId}
ORDER BY a.parent_id ASC

SELECT a.id, a.`name`, a.company_id pId, 'isDepartment' folderType, 1 isParent, '../../assets/images/department-icon.png' `icon`, '' `email` FROM company_department a
a.company_id IN
#{companyId}
AND a.id IN
#{departmentId}
AND a.tenant_id = #{tenantId}
